def play():
    try:
        for frame in frames:
            clear()
            print(frame)
            time.sleep(FRAME_DELAY)
        clear()
        print(blastoff)
        time.sleep(1.2)
    except KeyboardInterrupt:
        clear()
        print("Animation stopped.")
        sys.exit(0)

if __name__ == "__main__":
    if LOOP:
        while True:
            play()
    else:
        play()
